package be.schaubroeck.lpb.rkm.rekenmotor.service;

import be.schaubroeck.lpb.rkm.rekenmotor.CoreHrConfiguratie;
import be.schaubroeck.lpb.rkm.rekenmotor.RekenContext;
import be.schaubroeck.lpb.rkm.rekenmotor.RekenMotorStrategy;
import be.schaubroeck.lpb.rkm.rekenmotor.RekenMotorStrategyFactory;
import be.schaubroeck.lpb.rkm.rekenmotor.RekenTijd;
import be.schaubroeck.lpb.rkm.rekenmotor.cache.CacheContext;
import be.schaubroeck.lpb.rkm.rekenmotor.cache.CacheContext.Scope;
import be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenActionType;
import be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey;
import be.schaubroeck.lpb.rkm.rekenmotor.mapkeys.RekenAtoom;
import be.schaubroeck.lpb.rkm.rekenmotor.service.ExtraSqlService.OpdrachtData;
import be.schaubroeck.lpb.rkm.rekenmotor.service.web.RekenProcesImp;
import be.schaubroeck.lpb.rkm.rekenmotor.util.MetaRekenFeedback;
import be.schaubroeck.lpb.rkm.rekenmotor.util.RekenFeedback;
import be.schaubroeck.lpb.tools.Admin;
import be.schaubroeck.lpb.tools.LockLog;
import be.schaubroeck.lpb.tools.api.dto.LockLogDTO;
import be.schaubroeck.lpb.tools.enums.LockItemId;
import be.schaubroeck.lpb.tools.enums.LockType;
import be.schaubroeck.lpb.tools.enumtypes.RekenLogStatus;
import be.schaubroeck.lpb.tools.enumtypes.Rekenmodus;
import be.schaubroeck.lpb.tools.exception.ProcesHaltedException;
import be.schaubroeck.lpb.tools.service.LockLogService;
import be.schaubroeck.temporal.interval.LocalDateInterval;
import be.schaubroeck.temporal.interval.Month;
import be.schaubroeck.temporal.util.TemporalContext;
import com.google.common.collect.ImmutableList;
import com.google.common.collect.Multimap;
import com.google.common.collect.SetMultimap;
import com.google.common.collect.TreeMultimap;
import lombok.extern.slf4j.Slf4j;
import org.joda.time.LocalDate;
import org.joda.time.LocalDateTime;
import org.springframework.beans.factory.annotation.Autowired;

import java.util.ArrayList;
import java.util.Collection;
import java.util.List;
import java.util.Set;

@Slf4j
public class StandaardRekenUitBerekendenService implements RekenUitBerekendenService {

    @Autowired
    private RekenmotorService rekenmotorService;
    @Autowired
    private RekenMotorStrategyFactory rekenMotorStrategyFactory;
    @Autowired
    private LockLogService lockLogService;
    @Autowired
    private RekenenHelpService rekenenHelpService;
    @Autowired
    private ExtraSqlService extraSqlService;
    @Autowired
    private CoreHrConfigurationService coreHrConfigurationService;

    private static final int REKENEN_ITEMNR = 9;

    private static final List<LockLogDTO> LOCKS = ImmutableList.of(new LockLogDTO(LockItemId.ALLPID, REKENEN_ITEMNR, LockType.SHARED),
            new LockLogDTO(LockItemId.ALLREKENAGENDA, REKENEN_ITEMNR, LockType.SHARED),
            new LockLogDTO(LockItemId.ALLWACHTAGENDA, REKENEN_ITEMNR, LockType.SHARED),
            new LockLogDTO(LockItemId.ALLMT, REKENEN_ITEMNR, LockType.EXCLUSIVE));

    @Override
    public MetaRekenFeedback start(Admin admin, String actor, RekenContext actionParams) {
        return doeBerekeningen(admin, actor);
    }

    @Override
    public MetaRekenFeedback doeBerekeningen(Admin admin, String actor) {
        MetaRekenFeedback metaFeedback = new MetaRekenFeedback(RekenActionType.HERREKEN_ALLE_BEREKENDEN, Rekenmodus.NORMAAL);
        List<LockLog> lockedItems = new ArrayList<>();
        try {
            lockedItems = lockLogService.lockItems(admin, LOCKS, actor);
            CacheContext.getInstance().clearCachedServices(Scope.ALL);
            log.trace("doeBerekeningen(adminid:{} ({});", admin.getId(), admin.getAdminDirTrimmed());

            checkInterupted();
            SetMultimap<RekenAtoom, Integer> rekenAtomenMap = bepaalRekenAtomen(admin);
            metaFeedback.setRekenAtomen(rekenAtomenMap);
            schatAantalMaandOpdrachten(rekenAtomenMap.keySet());
            doeBerekeningenRekenAtomenNoCacheClear(admin, rekenAtomenMap, actor, metaFeedback);
        } finally {
            LockLogHelper lockLogHelper = new LockLogHelper(lockLogService, log);
            lockLogHelper.unlockItems(admin, lockedItems);
        }
        return metaFeedback;
    }

    @Override
    public SetMultimap<RekenAtoom, Integer> bepaalRekenAtomen(Admin admin) {
        LocalDateTime rekenTijdstip = TemporalContext.getInstance().getWerkTijdstip();
        LocalDateInterval actualInterval = TemporalContext.getInstance().getActualInterval();
        LocalDate rekenDatum = actualInterval.getEnd();
        LocalDateInterval periode = extraSqlService.bepaalPeriodeMaandtotalen(admin);
        Multimap<LocalDate, OpdrachtData> datumToOpdrachtDatas =
                extraSqlService.findOpdrachtenGebruiktInRekenResultaten(admin, periode.getStart(), periode.getEnd(), rekenTijdstip);

        SetMultimap<RekenAtoom, Integer> atomenMap = TreeMultimap.create();
        for (LocalDate datum : datumToOpdrachtDatas.keySet()) {
            Collection<OpdrachtData> opdrachtDatas = datumToOpdrachtDatas.get(datum);
            atomenMap.putAll(bepaalRekenAtomen(datum, opdrachtDatas, rekenDatum, rekenTijdstip));
        }
        return atomenMap;
    }

    private SetMultimap<RekenAtoom, Integer> bepaalRekenAtomen(
            LocalDate datum, Collection<OpdrachtData> opdrachtDatas, LocalDate rekenDatum, LocalDateTime rekenTijdstip) {
        log.trace("bepaalRekenAtomen({});", datum);
        SetMultimap<RekenAtoom, Integer> atomenMap = TreeMultimap.create();

        for (OpdrachtData opdracht : opdrachtDatas) {
            LocalDate beslagDatum = rekenDatum;
            LocalDate boekDatum = rekenDatum;
            LocalDateInterval rekenPeriode = new Month(datum);
            if (beslagDatum.isBefore(rekenPeriode.getStart())) {
                beslagDatum = rekenPeriode.getStart();
            }
            RekenTijd rekenTijd = new RekenTijd(rekenPeriode, rekenDatum, boekDatum, beslagDatum, rekenTijdstip);
            RekenAtoom atoom = new RekenAtoom(rekenTijd, opdracht.getPersoonId());
            atomenMap.put(atoom, opdracht.getOpdrachtnr());
        }

        return atomenMap;
    }

    private void schatAantalMaandOpdrachten(Set<RekenAtoom> rekenAtomen) {
        if (!rekenAtomen.isEmpty()) {
            RekenProcesImp.setTotaalStatic(rekenAtomen.size());
        } else {
            log.trace("Lege berekening");
            RekenProcesImp.setTotaalStatic(1);
            RekenProcesImp.incrementVerwerktStatic();
        }
    }

    private void doeBerekeningenRekenAtomenNoCacheClear(Admin admin, SetMultimap<RekenAtoom, Integer> rekenAtomenMap, String actor, MetaRekenFeedback metaFeedback) {
        RekenMotorStrategy strategy = rekenMotorStrategyFactory.getMaandTotalenStrategy(admin);
        RekenLogStatus status = RekenLogStatus.SUCCES;
        RekenContext rekenContext = new RekenContext();
        CoreHrConfiguratie coreHrConfiguratie = coreHrConfigurationService.getCoreHrConfiguratie(admin);

        for (RekenAtoom atoom : rekenAtomenMap.keySet()) {
            Set<Integer> opdrachtNrs = rekenAtomenMap.get(atoom);
            checkInterupted();
            try {
                rekenContext = rekenmotorService
                        .berekenLoon(admin, atoom.getPersoonId(), opdrachtNrs, atoom.getRekenTijd(), strategy, Rekenmodus.NORMAAL, actor, coreHrConfiguratie);

            } catch (Exception exception) {
                rekenenHelpService.logFatalException(admin, atoom.getRekenTijd().beginDatum, atoom.getPersoonId(), opdrachtNrs, exception);
                status = RekenLogStatus.FATAL_ERROR;
            }

            RekenFeedback rekenFeedback = metaFeedback.rekenFeedbackPerAtoom(atoom, rekenContext.getUnchecked(RekenChainKey.REKEN_FEEDBACK_KEY));
            RekenProcesImp.incrementVerwerktStatic();
            try {
                rekenenHelpService
                        .doeRekenLog(admin, atoom.getPersoonId(), opdrachtNrs, atoom.getRekenTijd(), Rekenmodus.NORMAAL, status, rekenFeedback, actor);
            } catch (Exception exception) {
                log.debug("Logging failed", exception);
            }
        }
    }

    private void checkInterupted() {
        if (RekenProcesImp.isInStopState()) {
            throw new ProcesHaltedException("Shall halt");
        }
    }

}
